  ('real-estate-moex-01302', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則之規定，以不動產證券化為估價目的，採折現現金流量分析法估價時，各期淨收 益應以勘估標的之何種租金為計算原則？', '["實質租金", "經濟租金", "支付租金", "契約租金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01303', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '因同種類不動產，由於技術革新、設計變化等，致使勘估標的落伍了，由此發生之建物折舊減價，屬於 下列何種折舊因素？', '["物理性", "外部性", "功能性", "經濟性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01304', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關直接資本化法的敘述，下列何者錯誤？', '["直接資本化法所求得之價格為收益價格", "指勘估標的過去平均一年期間之客觀淨收益，應用價格日期當時適當之收益資本化率推算勘估標的價 格之方法", "直接資本化法之收益資本化率可由加權平均資金成本法求取", "直接資本化法之客觀淨收益應以勘估標的作最有效使用之客觀淨收益為基準，並參酌鄰近類似不動產 在最有效使用情況下之收益推算之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01305', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關租金估價的敘述，下列何者正確？', '["續訂租約之租金屬正常租金", "不動產租金估計，應視新訂租約與續訂租約分別為之", "淨租金指承租人每期支付予出租人之租金，加計押金或保證金、權利金及其他相關運用收益之總數", "不動產租金估計，以估計勘估標的之支付租金為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01306', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關建物殘餘價格率之敘述，下列何者錯誤？', '["殘餘價格率是指建物於物理耐用年數屆滿後，其所賸餘之結構材料及內部設備仍能於市場上出售之價 格占建物總成本之比率", "建物之殘餘價格率應由不動產估價師公會全國聯合會公告", "建物之殘餘價格率以不超過百分之十為原則", "依殘餘價格率計算建物殘餘價格時，應考量建物耐用年數終止後所需清理或清除成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01307', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則之規定，下列何者並非由不動產估價師公會全國聯合會公告？', '["建物經濟耐用年數表", "建築改良物標準單價表", "營造或施工費標準表", "廣告費、銷售費、管理費及稅捐之相關費率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01308', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關房地估價之敘述，下列何者錯誤？', '["實際建築使用之容積率超過法定容積率之房地估價，應以實際建築使用之現況估價，並敘明法定容積對估 值之影響", "附有違章建築之房地估價，其違建部分不予以評估", "未達最有效使用狀態之房地估價，應先求取其最有效使用狀態之正常價格，再視其低度使用情況進行調整", "建物已不具備使用價值，得將其基地視為素地估價。但應考量建物拆除成本予以調整之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01309', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關比較法之敘述，下列何者錯誤？', '["比較標的價格為基礎，經比較、分析及調整等，以推算勘估標的價格之方法", "不動產估價師應採用五件以上比較標的", "區域因素及個別因素進行價格調整時，其調整以百分率法為原則", "以比較法所求得之價格為比較價格"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01310', 'real-estate', 'real-estate-moex-105-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關市地重劃估價的敘述，下列何者錯誤？', '["相關法令未明定重劃前後地價查估之價格日期", "重劃前之地價應分別估計各宗土地地價及區段價", "重劃後之地價應估計重劃後各路街之路線價或區段價", "估計重劃前後地價應提地價評議委員會評定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "8d0a6aafd352", "answer_pdf_sha1": "58e50b2aac5c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
